sql:
SELECT type, AVG(thc_percentage) AS average_thc_percentage
FROM strains
GROUP BY type;

SELECT 
  (SELECT AVG(rating) FROM reviews) AS avg_rating,
  (SELECT AVG(thc_percentage) FROM strains) AS avg_thc_percentage;

SELECT strain_id, COUNT(effect_id) AS effect_count
FROM effects
GROUP BY strain_id;

SELECT AVG(thc_percentage) AS average_thc_percentage
FROM strains
WHERE yield = 'Medium' AND flowering_time = '6-8 weeks';

external_knowledge:
- "garden of praise" metaphorically refers to the collection of high-rated strains (rating >= 4); 
- "those who speak highly" refers to users who have given high ratings;
- "whispers of their influence" refers to the effects of the strains;
- "gifts to health" refers to the medical benefits associated with the strains.

sql:
SELECT AVG(thc_percentage) AS average_thc_percentage
FROM strains
WHERE type = 'sativa' AND cbd_percentage > 0.5;

SELECT AVG(thc_percentage) AS average_thc_percentage
FROM strains
WHERE yield = 'High' AND difficulty_level = 'Easy';

SELECT type, COUNT(*) AS total_strains
FROM strains
GROUP BY type;

SELECT strain_id, name, type, description, thc_percentage, cbd_percentage, yield, flowering_time, difficulty_level, origin, seed_source, image_url
FROM strains
WHERE thc_percentage = (SELECT MAX(thc_percentage) FROM strains);
